/**
 * Timing utility functions for working with PrecisionTimestamp objects
 */

import type { PrecisionTimestamp } from '@psyforge/timing';

/**
 * Convert a PrecisionTimestamp to a numeric value for calculations
 */
export function timestampToNumber(timestamp: PrecisionTimestamp | number): number {
  if (typeof timestamp === 'number') {
    return timestamp;
  }
  return timestamp.monotonic;
}

/**
 * Calculate the difference between two timestamps
 */
export function timestampDiff(end: PrecisionTimestamp | number, start: PrecisionTimestamp | number): number {
  return timestampToNumber(end) - timestampToNumber(start);
}

/**
 * Add milliseconds to a timestamp
 */
export function timestampAdd(timestamp: PrecisionTimestamp | number, ms: number): number {
  return timestampToNumber(timestamp) + ms;
}

/**
 * Check if a timestamp has passed a certain time
 */
export function timestampHasPassed(timestamp: PrecisionTimestamp | number, targetTime: number): boolean {
  return timestampToNumber(timestamp) >= targetTime;
}

/**
 * Get the numeric value of a timestamp for storage or calculations
 */
export function getTimestampValue(timestamp: PrecisionTimestamp | number): number {
  return timestampToNumber(timestamp);
}

