import { z } from 'zod';
import type { TimelineItem, TimelineContext } from '../core/Timeline.js';
import { timestampToNumber } from '../utils/timing.js';

export interface MouseResponseData {
  x: number;
  y: number;
  button: number;
  timestamp: number;
  reactionTime: number;
  target?: string;
  correct?: boolean;
  metadata?: Record<string, unknown>;
}

export interface MouseResponseOptions {
  timeout?: number;
  message?: string;
  targets?: string[]; // CSS selectors or element IDs
  correctTarget?: string | ((context: TimelineContext) => string);
  allowedButtons?: number[]; // 0=left, 1=middle, 2=right
  cursor?: string;
  metadata?: Record<string, unknown>;
}

export class MouseResponse implements TimelineItem {
  public readonly id: string;
  private options: MouseResponseOptions;
  private responseData?: MouseResponseData;

  constructor(id: string, options: MouseResponseOptions = {}) {
    this.id = id;
    this.options = options;
  }

  timeout(ms: number): this {
    this.options.timeout = ms;
    return this;
  }

  message(text: string): this {
    this.options.message = text;
    return this;
  }

  targets(targetList: string[]): this {
    this.options.targets = targetList;
    return this;
  }

  correctTarget(target: string | ((context: TimelineContext) => string)): this {
    this.options.correctTarget = target;
    return this;
  }

  allowedButtons(buttons: number[]): this {
    this.options.allowedButtons = buttons;
    return this;
  }

  cursor(cursorType: string): this {
    this.options.cursor = cursorType;
    return this;
  }

  setMetadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private isButtonAllowed(button: number): boolean {
    if (!this.options.allowedButtons) {
      return true;
    }
    return this.options.allowedButtons.includes(button);
  }

  private isTargetValid(element: Element): boolean {
    if (!this.options.targets) {
      return true;
    }

    // Check if element matches any of the target selectors
    for (const target of this.options.targets) {
      if (element.matches(target) || element.id === target) {
        return true;
      }
    }

    return false;
  }

  private getTargetIdentifier(element: Element): string {
    if (element.id) {
      return `#${element.id}`;
    }
    if (element.className) {
      return `.${element.className.split(' ')[0]}`;
    }
    return element.tagName.toLowerCase();
  }

  private determineCorrectness(targetId: string, context: TimelineContext): boolean | undefined {
    if (!this.options.correctTarget) {
      return undefined;
    }

    const correctTarget = typeof this.options.correctTarget === 'function'
      ? this.options.correctTarget(context)
      : this.options.correctTarget;

    return targetId === correctTarget;
  }

  async execute(context: TimelineContext): Promise<void> {
    const startTime = context.clock.now();
    this.responseData = undefined;

    // Show message if provided
    let messageElement: HTMLElement | undefined;
    if (this.options.message) {
      messageElement = document.createElement('div');
      messageElement.textContent = this.options.message;
      messageElement.style.position = 'absolute';
      messageElement.style.top = '20px';
      messageElement.style.left = '50%';
      messageElement.style.transform = 'translateX(-50%)';
      messageElement.style.padding = '10px';
      messageElement.style.backgroundColor = 'rgba(0, 0, 0, 0.8)';
      messageElement.style.color = 'white';
      messageElement.style.borderRadius = '4px';
      messageElement.style.zIndex = '9999';
      document.body.appendChild(messageElement);
    }

    // Set cursor if specified
    const originalCursor = document.body.style.cursor;
    if (this.options.cursor) {
      document.body.style.cursor = this.options.cursor;
    }

    try {
      return new Promise((resolve) => {
        let timeoutId: number | undefined;
        let resolved = false;

        const handleMouseClick = (event: MouseEvent) => {
          if (resolved) return;

          const target = event.target as Element;
          const timestamp = context.clock.now();

          // Check if button is allowed
          if (!this.isButtonAllowed(event.button)) {
            return; // Ignore this click
          }

          // Check if target is valid (if targets are specified)
          if (!this.isTargetValid(target)) {
            return; // Ignore this click
          }

          // Prevent default behavior
          event.preventDefault();

          // Get target identifier
          const targetId = this.getTargetIdentifier(target);

          // Create response data
          this.responseData = {
            x: event.clientX,
            y: event.clientY,
            button: event.button,
            timestamp,
            reactionTime: timestamp - startTime,
            target: targetId,
            correct: this.determineCorrectness(targetId, context),
            metadata: this.options.metadata,
          };

          // Store response in context
          if (!context.data.responses) {
            context.data.responses = [];
          }
          (context.data.responses as MouseResponseData[]).push(this.responseData);

          // Clean up and resolve
          cleanup();
          resolved = true;
          resolve();
        };

        const handleTimeout = () => {
          if (resolved) return;

          // Create timeout response data
          this.responseData = {
            x: -1,
            y: -1,
            button: -1,
            timestamp: context.clock.now(),
            reactionTime: this.options.timeout!,
            target: '',
            correct: false,
            metadata: { ...this.options.metadata, timedOut: true },
          };

          // Store response in context
          if (!context.data.responses) {
            context.data.responses = [];
          }
          (context.data.responses as MouseResponseData[]).push(this.responseData);

          cleanup();
          resolved = true;
          resolve();
        };

        const cleanup = () => {
          document.removeEventListener('click', handleMouseClick);
          if (timeoutId !== undefined) {
            clearTimeout(timeoutId);
          }
          if (messageElement && messageElement.parentNode) {
            messageElement.parentNode.removeChild(messageElement);
          }
          // Restore cursor
          document.body.style.cursor = originalCursor;
        };

        // Set up mouse listener
        document.addEventListener('click', handleMouseClick);

        // Set up timeout if specified
        if (this.options.timeout) {
          timeoutId = window.setTimeout(handleTimeout, this.options.timeout);
        }
      });
    } catch (error) {
      // Clean up on error
      if (messageElement && messageElement.parentNode) {
        messageElement.parentNode.removeChild(messageElement);
      }
      document.body.style.cursor = originalCursor;
      throw error;
    }
  }

  getResponse(): MouseResponseData | undefined {
    return this.responseData;
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'MouseResponse',
      id: this.id,
      options: {
        ...this.options,
        // Note: correctTarget function cannot be serialized
        correctTarget: typeof this.options.correctTarget === 'string' 
          ? this.options.correctTarget 
          : '[Function]',
      },
      responseData: this.responseData,
    };
  }

  static deserialize(data: Record<string, unknown>): MouseResponse {
    const schema = z.object({
      id: z.string(),
      options: z.object({
        timeout: z.number().optional(),
        message: z.string().optional(),
        targets: z.array(z.string()).optional(),
        correctTarget: z.string().optional(),
        allowedButtons: z.array(z.number()).optional(),
        cursor: z.string().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new MouseResponse(parsed.id, parsed.options);
  }

  get duration(): number | undefined {
    return this.options.timeout;
  }

  get metadata(): Record<string, unknown> | undefined {
    return this.options.metadata;
  }
}

