          touchCount = Math.max(0, touchCount - event.changedTouches.length);
        };

        const handleTimeout = () => {
          if (resolved) return;

          // Create timeout response data
          this.responseData = {
            x: -1,
            y: -1,
            timestamp: context.clock.now(),
            reactionTime: this.options.timeout!,
            target: '',
            correct: false,
            touchId: -1,
            metadata: { ...this.options.metadata, timedOut: true },
          };

          // Store response in context
          if (!context.data.responses) {
            context.data.responses = [];
          }
          (context.data.responses as TouchResponseData[]).push(this.responseData);

