      },
      responseData: this.responseData,
    };
  }

  static deserialize(data: Record<string, unknown>): TouchResponse {
    const schema = z.object({
      id: z.string(),
      options: z.object({
        timeout: z.number().optional(),
        message: z.string().optional(),
        targets: z.array(z.string()).optional(),
        correctTarget: z.string().optional(),
        multiTouch: z.boolean().optional(),
        maxTouches: z.number().optional(),
        requireForce: z.boolean().optional(),
        minForce: z.number().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new TouchResponse(parsed.id, parsed.options);
  }

  get duration(): number | undefined {
    return this.options.timeout;
  }

  get metadata(): Record<string, unknown> | undefined {
    return this.options.metadata;
  }
}

