import { z } from 'zod';
import type { TimelineItem, TimelineContext } from '../core/Timeline.js';

export interface AudioStimulusOptions {
  duration?: number;
  volume?: number;
  loop?: boolean;
  autoplay?: boolean;
  preload?: boolean;
  fadeIn?: number;
  fadeOut?: number;
  startTime?: number;
  endTime?: number;
  metadata?: Record<string, unknown>;
}

export class AudioStimulus implements TimelineItem {
  public readonly id: string;
  private audioSrc: string | ((context: TimelineContext) => string);
  private options: AudioStimulusOptions;
  private element?: HTMLAudioElement;
  private preloadedAudio?: HTMLAudioElement;

  constructor(
    id: string,
    src: string | ((context: TimelineContext) => string),
    options: AudioStimulusOptions = {}
  ) {
    this.id = id;
    this.audioSrc = src;
    this.options = { 
      volume: 1.0,
      autoplay: true,
      preload: true,
      ...options 
    };
  }

  src(source: string | ((context: TimelineContext) => string)): this {
    this.audioSrc = source;
    return this;
  }

  setDuration(ms: number): this {
    this.options.duration = ms;
    return this;
  }

  volume(level: number): this {
    this.options.volume = Math.max(0, Math.min(1, level));
    return this;
  }

  loop(shouldLoop: boolean): this {
    this.options.loop = shouldLoop;
    return this;
  }

  autoplay(shouldAutoplay: boolean): this {
    this.options.autoplay = shouldAutoplay;
    return this;
  }

  preload(shouldPreload: boolean): this {
    this.options.preload = shouldPreload;
    return this;
  }

  fadeIn(ms: number): this {
    this.options.fadeIn = ms;
    return this;
  }

  fadeOut(ms: number): this {
    this.options.fadeOut = ms;
    return this;
  }

  startTime(seconds: number): this {
    this.options.startTime = seconds;
    return this;
  }

  endTime(seconds: number): this {
    this.options.endTime = seconds;
    return this;
  }

  setMetadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private async preloadAudio(src: string): Promise<HTMLAudioElement> {
    return new Promise((resolve, reject) => {
      const audio = new Audio();

      const handleCanPlayThrough = () => {
        audio.removeEventListener('canplaythrough', handleCanPlayThrough);
        audio.removeEventListener('error', handleError);
        resolve(audio);
      };

      const handleError = () => {
        audio.removeEventListener('canplaythrough', handleCanPlayThrough);
        audio.removeEventListener('error', handleError);
        reject(new Error(`Failed to load audio: ${src}`));
      };

      audio.addEventListener('canplaythrough', handleCanPlayThrough);
      audio.addEventListener('error', handleError);
      audio.src = src;
      audio.load();
    });
  }

  private createAudioElement(context: TimelineContext, preloadedAudio?: HTMLAudioElement): HTMLAudioElement {
    const element = preloadedAudio || new Audio();

    // Set source if not using preloaded audio
    if (!preloadedAudio) {
      const src = typeof this.audioSrc === 'function' 
        ? this.audioSrc(context) 
        : this.audioSrc;
      element.src = src;
    }

    // Apply audio properties
    if (this.options.volume !== undefined) {
      element.volume = this.options.volume;
    }
    if (this.options.loop !== undefined) {
      element.loop = this.options.loop;
    }

    // Set start position if specified
    if (this.options.startTime !== undefined) {
      element.currentTime = this.options.startTime;
    }

    return element;
  }

  private async applyFadeIn(audio: HTMLAudioElement, duration: number): Promise<void> {
    const originalVolume = audio.volume;
    audio.volume = 0;

    const steps = 50;
    const stepDuration = duration / steps;
    const volumeStep = originalVolume / steps;

    for (let i = 0; i <= steps; i++) {
      audio.volume = volumeStep * i;
      await new Promise(resolve => setTimeout(resolve, stepDuration));
    }
  }

  private async applyFadeOut(audio: HTMLAudioElement, duration: number): Promise<void> {
    const originalVolume = audio.volume;

    const steps = 50;
    const stepDuration = duration / steps;
    const volumeStep = originalVolume / steps;

    for (let i = steps; i >= 0; i--) {
      audio.volume = volumeStep * i;
      await new Promise(resolve => setTimeout(resolve, stepDuration));
    }
  }

  async execute(context: TimelineContext): Promise<void> {
    const startTime = context.clock.now();

    // Get source
    const src = typeof this.audioSrc === 'function' 
      ? this.audioSrc(context) 
      : this.audioSrc;

    // Preload audio if requested and not already preloaded
    if (this.options.preload && !this.preloadedAudio) {
      try {
        this.preloadedAudio = await this.preloadAudio(src);
      } catch (error) {
        console.warn(`Failed to preload audio: ${src}`, error);
      }
    }

    // Create audio element
    this.element = this.createAudioElement(context, this.preloadedAudio);

    // Wait for audio to be ready if not preloaded
    if (!this.preloadedAudio) {
      await new Promise<void>((resolve, reject) => {
        const handleCanPlay = () => {
          this.element!.removeEventListener('canplay', handleCanPlay);
          this.element!.removeEventListener('error', handleError);
          resolve();
        };

        const handleError = () => {
          this.element!.removeEventListener('canplay', handleCanPlay);
          this.element!.removeEventListener('error', handleError);
          reject(new Error(`Failed to load audio: ${src}`));
        };

        this.element!.addEventListener('canplay', handleCanPlay);
        this.element!.addEventListener('error', handleError);

        // If already ready, resolve immediately
        if (this.element!.readyState >= 3) { // HAVE_FUTURE_DATA
          resolve();
        }
      });
    }

    // Start playback if autoplay is enabled
    if (this.options.autoplay) {
      try {
        await this.element.play();

        // Apply fade in effect
        if (this.options.fadeIn) {
          await this.applyFadeIn(this.element, this.options.fadeIn);
        }
      } catch (error) {
        console.warn('Audio playback failed:', error);
      }
    }

    // Handle duration and fade out
    if (this.options.duration) {
      return new Promise((resolve) => {
        const checkTime = () => {
          const elapsed = context.clock.now() - startTime;

          // Start fade out if specified
          if (this.options.fadeOut && elapsed >= (this.options.duration! - this.options.fadeOut)) {
            this.applyFadeOut(this.element!, this.options.fadeOut);
          }

          // Check end time if specified
          if (this.options.endTime && this.element!.currentTime >= this.options.endTime) {
            this.cleanup();
            resolve();
            return;
          }

          if (elapsed >= this.options.duration!) {
            this.cleanup();
            resolve();
          } else {
            requestAnimationFrame(checkTime);
          }
        };
        checkTime();
      });
    } else if (this.options.endTime) {
      // Wait until audio reaches end time
      return new Promise((resolve) => {
        const checkTime = () => {
          if (this.element!.currentTime >= this.options.endTime! || this.element!.ended) {
            this.cleanup();
            resolve();
          } else {
            requestAnimationFrame(checkTime);
          }
        };
        checkTime();
      });
    } else {
      // Wait until audio ends naturally
      return new Promise((resolve) => {
        const handleEnded = () => {
          this.cleanup();
          resolve();
        };
        this.element!.addEventListener('ended', handleEnded, { once: true });
      });
    }
  }

  private cleanup(): void {
    if (this.element) {
      this.element.pause();
      this.element.currentTime = 0;
      this.element = undefined;
    }
  }

  stop(): void {
    this.cleanup();
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'AudioStimulus',
      id: this.id,
      src: typeof this.audioSrc === 'string' ? this.audioSrc : '[Function]',
      options: this.options,
    };
  }

  static deserialize(data: Record<string, unknown>): AudioStimulus {
    const schema = z.object({
      id: z.string(),
      src: z.string(),
      options: z.object({
        duration: z.number().optional(),
        volume: z.number().optional(),
        loop: z.boolean().optional(),
        autoplay: z.boolean().optional(),
        preload: z.boolean().optional(),
        fadeIn: z.number().optional(),
        fadeOut: z.number().optional(),
        startTime: z.number().optional(),
        endTime: z.number().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new AudioStimulus(parsed.id, parsed.src, parsed.options);
  }

  get duration(): number | undefined {
    return this.options.duration;
  }

  get metadata(): Record<string, unknown> | undefined {
    return this.options.metadata;
  }
}

