import { z } from 'zod';
import type { TimelineItem, TimelineContext } from '../core/Timeline.js';
import { 
  sanitizeUrl, 
  sanitizeClassName, 
  sanitizeStyleValue, 
  sanitizeTextContent, 
  sanitizeNumericValue 
} from '../utils/security.js';

export interface ImageStimulusOptions {
  duration?: number;
  position?: { x: number; y: number };
  size?: { width: number; height: number };
  opacity?: number;
  rotation?: number;
  scale?: number;
  zIndex?: number;
  className?: string;
  style?: Record<string, string>;
  preload?: boolean;
  alt?: string;
  metadata?: Record<string, unknown>;
}

export class ImageStimulus implements TimelineItem {
  public readonly id: string;
  private imageSrc: string | ((context: TimelineContext) => string);
  private options: ImageStimulusOptions;
  private element?: HTMLImageElement;
  private preloadedImage?: HTMLImageElement;

  constructor(
    id: string,
    src: string | ((context: TimelineContext) => string),
    options: ImageStimulusOptions = {}
  ) {
    this.id = id;
    this.imageSrc = src;
    this.options = { preload: true, ...options };
  }

  src(source: string | ((context: TimelineContext) => string)): this {
    this.imageSrc = source;
    return this;
  }

  setDuration(ms: number): this {
    this.options.duration = ms;
    return this;
  }

  position(x: number, y: number): this {
    this.options.position = { x, y };
    return this;
  }

  size(width: number, height: number): this {
    this.options.size = { width, height };
    return this;
  }

  opacity(alpha: number): this {
    this.options.opacity = Math.max(0, Math.min(1, alpha));
    return this;
  }

  rotation(degrees: number): this {
    this.options.rotation = degrees;
    return this;
  }

  scale(factor: number): this {
    this.options.scale = factor;
    return this;
  }

  zIndex(z: number): this {
    this.options.zIndex = z;
    return this;
  }

  className(name: string): this {
    const sanitized = sanitizeClassName(name);
    if (sanitized) {
      this.options.className = sanitized;
    }
    return this;
  }

  style(styles: Record<string, string>): this {
    const sanitizedStyles: Record<string, string> = {};

    for (const [property, value] of Object.entries(styles)) {
      const sanitizedValue = sanitizeStyleValue(property, value);
      if (sanitizedValue) {
        sanitizedStyles[property] = sanitizedValue;
      }
    }

    this.options.style = { ...this.options.style, ...sanitizedStyles };
    return this;
  }

  preload(shouldPreload: boolean): this {
    this.options.preload = shouldPreload;
    return this;
  }

  alt(altText: string): this {
    this.options.alt = sanitizeTextContent(altText);
    return this;
  }

  setMetadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private async preloadImage(src: string): Promise<HTMLImageElement> {
    return new Promise((resolve, reject) => {
      const sanitizedSrc = sanitizeUrl(src);
      if (!sanitizedSrc) {
        reject(new Error(`Invalid image URL: ${src}`));
        return;
      }

      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = sanitizedSrc;
    });
  }

  private createImageElement(context: TimelineContext, preloadedImg?: HTMLImageElement): HTMLImageElement {
    const element = preloadedImg ? preloadedImg.cloneNode() as HTMLImageElement : new Image();

    // Set source if not using preloaded image
    if (!preloadedImg) {
      const src = typeof this.imageSrc === 'function' 
        ? this.imageSrc(context) 
        : this.imageSrc;
      const sanitizedSrc = sanitizeUrl(src);
      if (sanitizedSrc) {
        element.src = sanitizedSrc;
      }
    }

    // Apply basic styles
    element.style.position = 'absolute';
    element.style.pointerEvents = 'none';

    // Apply position
    if (this.options.position) {
      element.style.left = `${this.options.position.x}px`;
      element.style.top = `${this.options.position.y}px`;
    } else {
      // Center by default
      element.style.left = '50%';
      element.style.top = '50%';
      element.style.transform = 'translate(-50%, -50%)';
    }

    // Apply size
    if (this.options.size) {
      element.style.width = `${this.options.size.width}px`;
      element.style.height = `${this.options.size.height}px`;
    }

    // Apply visual effects
    if (this.options.opacity !== undefined) {
      element.style.opacity = this.options.opacity.toString();
    }
    if (this.options.rotation !== undefined) {
      const currentTransform = element.style.transform || '';
      element.style.transform = `${currentTransform} rotate(${this.options.rotation}deg)`;
    }
    if (this.options.scale !== undefined) {
      const currentTransform = element.style.transform || '';
      element.style.transform = `${currentTransform} scale(${this.options.scale})`;
    }
    if (this.options.zIndex !== undefined) {
      element.style.zIndex = this.options.zIndex.toString();
    }

    // Apply CSS class
    if (this.options.className) {
      element.className = this.options.className;
    }

    // Apply custom styles with sanitization
    if (this.options.style) {
      for (const [property, value] of Object.entries(this.options.style)) {
        const sanitizedValue = sanitizeStyleValue(property, value);
        if (sanitizedValue) {
          (element.style as any)[property] = sanitizedValue;
        }
      }
    }

    // Set alt text
    if (this.options.alt) {
      element.alt = this.options.alt; // Already sanitized in alt() method
    }

    return element;
  }

  async execute(context: TimelineContext): Promise<void> {
    const startTime = context.clock.now();

    // Get source
    const src = typeof this.imageSrc === 'function' 
      ? this.imageSrc(context) 
      : this.imageSrc;

    // Preload image if requested and not already preloaded
    if (this.options.preload && !this.preloadedImage) {
      try {
        this.preloadedImage = await this.preloadImage(src);
      } catch (error) {
        console.warn(`Failed to preload image: ${src}`, error);
      }
    }

    // Create and display element
    this.element = this.createImageElement(context, this.preloadedImage);

    // Handle image loading if not preloaded
    if (!this.preloadedImage) {
      await new Promise<void>((resolve, reject) => {
        this.element!.onload = () => resolve();
        this.element!.onerror = reject;
        // If image is already loaded (cached), resolve immediately
        if (this.element!.complete) {
          resolve();
        }
      });
    }

    document.body.appendChild(this.element);

    // Wait for duration if specified
    if (this.options.duration) {
      return new Promise((resolve) => {
        const checkTime = () => {
          const elapsed = context.clock.now() - startTime;
          if (elapsed >= this.options.duration!) {
            this.cleanup();
            resolve();
          } else {
            requestAnimationFrame(checkTime);
          }
        };
        checkTime();
      });
    }
  }

  private cleanup(): void {
    if (this.element && this.element.parentNode) {
      this.element.parentNode.removeChild(this.element);
      this.element = undefined;
    }
  }

  hide(): void {
    this.cleanup();
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'ImageStimulus',
      id: this.id,
      src: typeof this.imageSrc === 'string' ? this.imageSrc : '[Function]',
      options: {
        ...this.options,
        // Remove non-serializable style object for now
        style: undefined,
      },
    };
  }

  static deserialize(data: Record<string, unknown>): ImageStimulus {
    const schema = z.object({
      id: z.string(),
      src: z.string(),
      options: z.object({
        duration: z.number().optional(),
        position: z.object({ x: z.number(), y: z.number() }).optional(),
        size: z.object({ width: z.number(), height: z.number() }).optional(),
        opacity: z.number().optional(),
        rotation: z.number().optional(),
        scale: z.number().optional(),
        zIndex: z.number().optional(),
        className: z.string().optional(),
        preload: z.boolean().optional(),
        alt: z.string().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new ImageStimulus(parsed.id, parsed.src, parsed.options);
  }

  get duration(): number | undefined {
    return this.options.duration;
  }

  get metadata(): Record<string, unknown> | undefined {
    return this.options.metadata;
  }
}

