import { z } from 'zod';
import type { TimelineItem, TimelineContext } from '../core/Timeline.js';

export interface VideoStimulusOptions {
  duration?: number;
  position?: { x: number; y: number };
  size?: { width: number; height: number };
  volume?: number;
  muted?: boolean;
  loop?: boolean;
  autoplay?: boolean;
  preload?: boolean;
  controls?: boolean;
  opacity?: number;
  rotation?: number;
  scale?: number;
  zIndex?: number;
  className?: string;
  style?: Record<string, string>;
  startTime?: number;
  endTime?: number;
  playbackRate?: number;
  metadata?: Record<string, unknown>;
}

export class VideoStimulus implements TimelineItem {
  public readonly id: string;
  private videoSrc: string | ((context: TimelineContext) => string);
  private options: VideoStimulusOptions;
  private element?: HTMLVideoElement;
  private preloadedVideo?: HTMLVideoElement;

  constructor(
    id: string,
    src: string | ((context: TimelineContext) => string),
    options: VideoStimulusOptions = {}
  ) {
    this.id = id;
    this.videoSrc = src;
    this.options = { 
      volume: 1.0,
      muted: false,
      autoplay: true,
      preload: true,
      controls: false,
      playbackRate: 1.0,
      ...options 
    };
  }

  src(source: string | ((context: TimelineContext) => string)): this {
    this.videoSrc = source;
    return this;
  }

  setDuration(ms: number): this {
    this.options.duration = ms;
    return this;
  }

  position(x: number, y: number): this {
    this.options.position = { x, y };
    return this;
  }

  size(width: number, height: number): this {
    this.options.size = { width, height };
    return this;
  }

  volume(level: number): this {
    this.options.volume = Math.max(0, Math.min(1, level));
    return this;
  }

  muted(isMuted: boolean): this {
    this.options.muted = isMuted;
    return this;
  }

  loop(shouldLoop: boolean): this {
    this.options.loop = shouldLoop;
    return this;
  }

  autoplay(shouldAutoplay: boolean): this {
    this.options.autoplay = shouldAutoplay;
    return this;
  }

  preload(shouldPreload: boolean): this {
    this.options.preload = shouldPreload;
    return this;
  }

  controls(showControls: boolean): this {
    this.options.controls = showControls;
    return this;
  }

  opacity(alpha: number): this {
    this.options.opacity = Math.max(0, Math.min(1, alpha));
    return this;
  }

  rotation(degrees: number): this {
    this.options.rotation = degrees;
    return this;
  }

  scale(factor: number): this {
    this.options.scale = factor;
    return this;
  }

  zIndex(z: number): this {
    this.options.zIndex = z;
    return this;
  }

  className(name: string): this {
    this.options.className = name;
    return this;
  }

  style(styles: Record<string, string>): this {
    this.options.style = { ...this.options.style, ...styles };
    return this;
  }

  startTime(seconds: number): this {
    this.options.startTime = seconds;
    return this;
  }

  endTime(seconds: number): this {
    this.options.endTime = seconds;
    return this;
  }

  playbackRate(rate: number): this {
    this.options.playbackRate = rate;
    return this;
  }

  setMetadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private async preloadVideo(src: string): Promise<HTMLVideoElement> {
    return new Promise((resolve, reject) => {
      const video = document.createElement('video');

      const handleCanPlayThrough = () => {
        video.removeEventListener('canplaythrough', handleCanPlayThrough);
        video.removeEventListener('error', handleError);
        resolve(video);
      };

      const handleError = () => {
        video.removeEventListener('canplaythrough', handleCanPlayThrough);
        video.removeEventListener('error', handleError);
        reject(new Error(`Failed to load video: ${src}`));
      };

      video.addEventListener('canplaythrough', handleCanPlayThrough);
      video.addEventListener('error', handleError);
      video.src = src;
      video.load();
    });
  }

  private createVideoElement(context: TimelineContext, preloadedVideo?: HTMLVideoElement): HTMLVideoElement {
    const element = preloadedVideo ? preloadedVideo.cloneNode() as HTMLVideoElement : document.createElement('video');

    // Set source if not using preloaded video
    if (!preloadedVideo) {
      const src = typeof this.videoSrc === 'function' 
        ? this.videoSrc(context) 
        : this.videoSrc;
      element.src = src;
    }

    // Apply basic styles
    element.style.position = 'absolute';
    if (!this.options.controls) {
      element.style.pointerEvents = 'none';
    }

    // Apply position
    if (this.options.position) {
      element.style.left = `${this.options.position.x}px`;
      element.style.top = `${this.options.position.y}px`;
    } else {
      // Center by default
      element.style.left = '50%';
      element.style.top = '50%';
      element.style.transform = 'translate(-50%, -50%)';
    }

    // Apply size
    if (this.options.size) {
      element.style.width = `${this.options.size.width}px`;
      element.style.height = `${this.options.size.height}px`;
    }

    // Apply video properties
    if (this.options.volume !== undefined) {
      element.volume = this.options.volume;
    }
    if (this.options.muted !== undefined) {
      element.muted = this.options.muted;
    }
    if (this.options.loop !== undefined) {
      element.loop = this.options.loop;
    }
    if (this.options.controls !== undefined) {
      element.controls = this.options.controls;
    }
    if (this.options.playbackRate !== undefined) {
      element.playbackRate = this.options.playbackRate;
    }

    // Apply visual effects
    if (this.options.opacity !== undefined) {
      element.style.opacity = this.options.opacity.toString();
    }
    if (this.options.rotation !== undefined) {
      const currentTransform = element.style.transform || '';
      element.style.transform = `${currentTransform} rotate(${this.options.rotation}deg)`;
    }
    if (this.options.scale !== undefined) {
      const currentTransform = element.style.transform || '';
      element.style.transform = `${currentTransform} scale(${this.options.scale})`;
    }
    if (this.options.zIndex !== undefined) {
      element.style.zIndex = this.options.zIndex.toString();
    }

    // Apply CSS class
    if (this.options.className) {
      element.className = this.options.className;
    }

    // Apply custom styles
    if (this.options.style) {
      Object.assign(element.style, this.options.style);
    }

    // Set start position if specified
    if (this.options.startTime !== undefined) {
      element.currentTime = this.options.startTime;
    }

    return element;
  }

  async execute(context: TimelineContext): Promise<void> {
    const startTime = context.clock.now();

    // Get source
    const src = typeof this.videoSrc === 'function' 
      ? this.videoSrc(context) 
      : this.videoSrc;

    // Preload video if requested and not already preloaded
    if (this.options.preload && !this.preloadedVideo) {
      try {
        this.preloadedVideo = await this.preloadVideo(src);
      } catch (error) {
        console.warn(`Failed to preload video: ${src}`, error);
      }
    }

    // Create video element
    this.element = this.createVideoElement(context, this.preloadedVideo);

    // Wait for video to be ready if not preloaded
    if (!this.preloadedVideo) {
      await new Promise<void>((resolve, reject) => {
        const handleCanPlay = () => {
          this.element!.removeEventListener('canplay', handleCanPlay);
          this.element!.removeEventListener('error', handleError);
          resolve();
        };

        const handleError = () => {
          this.element!.removeEventListener('canplay', handleCanPlay);
          this.element!.removeEventListener('error', handleError);
          reject(new Error(`Failed to load video: ${src}`));
        };

        this.element!.addEventListener('canplay', handleCanPlay);
        this.element!.addEventListener('error', handleError);

        // If already ready, resolve immediately
        if (this.element!.readyState >= 3) { // HAVE_FUTURE_DATA
          resolve();
        }
      });
    }

    // Add to DOM
    document.body.appendChild(this.element);

    // Start playback if autoplay is enabled
    if (this.options.autoplay) {
      try {
        await this.element.play();
      } catch (error) {
        console.warn('Video playback failed:', error);
      }
    }

    // Handle duration
    if (this.options.duration) {
      return new Promise((resolve) => {
        const checkTime = () => {
          const elapsed = context.clock.now() - startTime;

          // Check end time if specified
          if (this.options.endTime && this.element!.currentTime >= this.options.endTime) {
            this.cleanup();
            resolve();
            return;
          }

          if (elapsed >= this.options.duration!) {
            this.cleanup();
            resolve();
          } else {
            requestAnimationFrame(checkTime);
          }
        };
        checkTime();
      });
    } else if (this.options.endTime) {
      // Wait until video reaches end time
      return new Promise((resolve) => {
        const checkTime = () => {
          if (this.element!.currentTime >= this.options.endTime! || this.element!.ended) {
            this.cleanup();
            resolve();
          } else {
            requestAnimationFrame(checkTime);
          }
        };
        checkTime();
      });
    } else {
      // Wait until video ends naturally
      return new Promise((resolve) => {
        const handleEnded = () => {
          this.cleanup();
          resolve();
        };
        this.element!.addEventListener('ended', handleEnded, { once: true });
      });
    }
  }

  private cleanup(): void {
    if (this.element) {
      this.element.pause();
      if (this.element.parentNode) {
        this.element.parentNode.removeChild(this.element);
      }
      this.element = undefined;
    }
  }

  stop(): void {
    this.cleanup();
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'VideoStimulus',
      id: this.id,
      src: typeof this.videoSrc === 'string' ? this.videoSrc : '[Function]',
      options: {
        ...this.options,
        // Remove non-serializable style object for now
        style: undefined,
      },
    };
  }

  static deserialize(data: Record<string, unknown>): VideoStimulus {
    const schema = z.object({
      id: z.string(),
      src: z.string(),
      options: z.object({
        duration: z.number().optional(),
        position: z.object({ x: z.number(), y: z.number() }).optional(),
        size: z.object({ width: z.number(), height: z.number() }).optional(),
        volume: z.number().optional(),
        muted: z.boolean().optional(),
        loop: z.boolean().optional(),
        autoplay: z.boolean().optional(),
        preload: z.boolean().optional(),
        controls: z.boolean().optional(),
        opacity: z.number().optional(),
        rotation: z.number().optional(),
        scale: z.number().optional(),
        zIndex: z.number().optional(),
        className: z.string().optional(),
        startTime: z.number().optional(),
        endTime: z.number().optional(),
        playbackRate: z.number().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new VideoStimulus(parsed.id, parsed.src, parsed.options);
  }

  get duration(): number | undefined {
    return this.options.duration;
  }

  get metadata(): Record<string, unknown> | undefined {
    return this.options.metadata;
  }
}

