import { BaseComponent, type ComponentContext } from '../BaseComponent.js';

export type EasingFunction = 
  | 'linear'
  | 'easeIn'
  | 'easeOut'
  | 'easeInOut'
  | 'bounceIn'
  | 'bounceOut'
  | 'bounceInOut'
  | 'elasticIn'
  | 'elasticOut'
  | 'elasticInOut'
  | ((t: number) => number);

export interface AnimationKeyframe {
  time: number; // 0-1, normalized time
  position?: { x: number; y: number; z?: number };
  rotation?: number;
  scale?: { x: number; y: number };
  opacity?: number;
  easing?: EasingFunction;
}

export interface AnimationOptions {
  duration: number; // in milliseconds
  keyframes?: AnimationKeyframe[];
  loop?: boolean | number; // true for infinite, number for specific count
  reverse?: boolean;
  delay?: number;
  autoStart?: boolean;
  onComplete?: () => void | Promise<void>;
  onLoop?: (iteration: number) => void | Promise<void>;
}

export class AnimationComponent extends BaseComponent {
  private options: AnimationOptions;
  private target?: BaseComponent;
  private startTime = 0;
  private isPlaying = false;
  private isPaused = false;
  private currentIteration = 0;
  private initialTransform?: any;
  private animationId?: number;

  constructor(id: string, target: BaseComponent, options: AnimationOptions) {
    super(id, 'Animation');
    this.target = target;
    this.options = { autoStart: true, ...options };
  }

  // Fluent API for creating animations
  static fadeIn(id: string, target: BaseComponent, duration = 500): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0, opacity: 0 },
        { time: 1, opacity: 1, easing: 'easeOut' }
      ]
    });
  }

  static fadeOut(id: string, target: BaseComponent, duration = 500): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0, opacity: 1 },
        { time: 1, opacity: 0, easing: 'easeIn' }
      ]
    });
  }

  static move(id: string, target: BaseComponent, toPosition: { x: number; y: number }, duration = 1000): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0 }, // Uses current position
        { time: 1, position: toPosition, easing: 'easeInOut' }
      ]
    });
  }

  static scale(id: string, target: BaseComponent, toScale: number | { x: number; y: number }, duration = 500): AnimationComponent {
    const scaleObj = typeof toScale === 'number' ? { x: toScale, y: toScale } : toScale;
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0 }, // Uses current scale
        { time: 1, scale: scaleObj, easing: 'bounceOut' }
      ]
    });
  }

  static rotate(id: string, target: BaseComponent, toDegrees: number, duration = 1000): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0 }, // Uses current rotation
        { time: 1, rotation: toDegrees, easing: 'easeInOut' }
      ]
    });
  }

  static bounce(id: string, target: BaseComponent, height = 50, duration = 800): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0, easing: 'easeOut' },
        { time: 0.5, position: { x: 0, y: -height }, easing: 'easeIn' },
        { time: 1, easing: 'bounceOut' }
      ]
    });
  }

  static pulse(id: string, target: BaseComponent, maxScale = 1.2, duration = 600): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      loop: true,
      keyframes: [
        { time: 0, scale: { x: 1, y: 1 }, easing: 'easeInOut' },
        { time: 0.5, scale: { x: maxScale, y: maxScale }, easing: 'easeInOut' },
        { time: 1, scale: { x: 1, y: 1 }, easing: 'easeInOut' }
      ]
    });
  }

  static shake(id: string, target: BaseComponent, intensity = 10, duration = 400): AnimationComponent {
    return new AnimationComponent(id, target, {
      duration,
      keyframes: [
        { time: 0 },
        { time: 0.1, position: { x: intensity, y: 0 } },
        { time: 0.2, position: { x: -intensity, y: 0 } },
        { time: 0.3, position: { x: intensity, y: 0 } },
        { time: 0.4, position: { x: -intensity, y: 0 } },
        { time: 0.5, position: { x: intensity, y: 0 } },
        { time: 0.6, position: { x: -intensity, y: 0 } },
        { time: 0.7, position: { x: intensity, y: 0 } },
        { time: 0.8, position: { x: -intensity, y: 0 } },
        { time: 0.9, position: { x: intensity / 2, y: 0 } },
        { time: 1, position: { x: 0, y: 0 } }
      ]
    });
  }

  // Fluent configuration methods
  loop(count: boolean | number = true): this {
    this.options.loop = count;
    return this;
  }

  reverse(shouldReverse = true): this {
    this.options.reverse = shouldReverse;
    return this;
  }

  delay(ms: number): this {
    this.options.delay = ms;
    return this;
  }

  onComplete(handler: () => void | Promise<void>): this {
    this.options.onComplete = handler;
    return this;
  }

  onLoop(handler: (iteration: number) => void | Promise<void>): this {
    this.options.onLoop = handler;
    return this;
  }

  async onInit(context: ComponentContext): Promise<void> {
    if (!this.target) {
      throw new Error('Animation target is required');
    }

    // Store initial transform state
    this.initialTransform = {
      position: { ...this.target.worldPosition },
      rotation: (this.target as any).transform.rotation,
      scale: { ...(this.target as any).transform.scale },
      opacity: (this.target as any).transform.opacity,
    };

    if (this.options.autoStart) {
      this.play(context);
    }
  }

  onFrame(deltaTime: number, context: ComponentContext): void {
    if (!this.isPlaying || this.isPaused || !this.target) {
      return;
    }

    const currentTime = context.clock.now();
    const elapsed = currentTime - this.startTime;

    // Handle delay
    if (this.options.delay && elapsed < this.options.delay) {
      return;
    }

    const animationElapsed = elapsed - (this.options.delay || 0);
    let progress = animationElapsed / this.options.duration;

    // Handle reverse
    if (this.options.reverse) {
      progress = 1 - progress;
    }

    // Clamp progress
    progress = Math.max(0, Math.min(1, progress));

    // Apply animation
    this.applyKeyframes(progress);

    // Check for completion
    if (progress >= 1) {
      this.handleCompletion();
    }
  }

  async onDispose(context: ComponentContext): Promise<void> {
    this.stop();
  }

  private applyKeyframes(progress: number): void {
    if (!this.target || !this.options.keyframes) {
      return;
    }

    // Find surrounding keyframes
    const keyframes = this.options.keyframes.sort((a, b) => a.time - b.time);
    let startKeyframe = keyframes[0];
    let endKeyframe = keyframes[keyframes.length - 1];

    for (let i = 0; i < keyframes.length - 1; i++) {
      if (progress >= keyframes[i].time && progress <= keyframes[i + 1].time) {
        startKeyframe = keyframes[i];
        endKeyframe = keyframes[i + 1];
        break;
      }
    }

    // Calculate local progress between keyframes
    const keyframeDuration = endKeyframe.time - startKeyframe.time;
    const localProgress = keyframeDuration > 0 
      ? (progress - startKeyframe.time) / keyframeDuration 
      : 1;

    // Apply easing
    const easing = endKeyframe.easing || 'linear';
    const easedProgress = this.applyEasing(localProgress, easing);

    // Interpolate values
    this.interpolateTransform(startKeyframe, endKeyframe, easedProgress);
  }

  private interpolateTransform(start: AnimationKeyframe, end: AnimationKeyframe, progress: number): void {
    if (!this.target) return;

    const targetTransform = (this.target as any).transform;

    // Position interpolation
    if (end.position) {
      const startPos = start.position || this.initialTransform.position;
      const endPos = end.position;

      const x = this.lerp(startPos.x, endPos.x, progress);
      const y = this.lerp(startPos.y, endPos.y, progress);
      const z = endPos.z !== undefined ? this.lerp(startPos.z || 0, endPos.z, progress) : undefined;

      this.target.position(x, y, z);
    }

    // Rotation interpolation
    if (end.rotation !== undefined) {
      const startRot = start.rotation !== undefined ? start.rotation : this.initialTransform.rotation;
      const endRot = end.rotation;

      const rotation = this.lerp(startRot, endRot, progress);
      this.target.rotate(rotation);
    }

    // Scale interpolation
    if (end.scale) {
      const startScale = start.scale || this.initialTransform.scale;
      const endScale = end.scale;

      const scaleX = this.lerp(startScale.x, endScale.x, progress);
      const scaleY = this.lerp(startScale.y, endScale.y, progress);

      this.target.scale(scaleX, scaleY);
    }

    // Opacity interpolation
    if (end.opacity !== undefined) {
      const startOpacity = start.opacity !== undefined ? start.opacity : this.initialTransform.opacity;
      const endOpacity = end.opacity;

      const opacity = this.lerp(startOpacity, endOpacity, progress);
