      clearTimeout(this.timeoutTimer);
      this.timeoutTimer = undefined;
    }
  }

  reset(): void {
    this.stopListening();
    this.hasResponded = false;
    this.startTime = 0;
  }

  // State getters
  get listening(): boolean {
    return this.isListening;
  }

  get responded(): boolean {
    return this.hasResponded;
  }

  get elapsedTime(): number {
    if (this.startTime === 0) {
      return 0;
    }
    return performance.now() - this.startTime;
  }

  // Convenience methods for common use cases
  static waitForAnyKey(id = 'keyboard-any', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { timeout });
  }

  static waitForKeys(keys: string[], id = 'keyboard-specific', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { allowedKeys: keys, timeout });
  }

  static waitForSpacebar(id = 'keyboard-space', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { allowedKeys: [' ', 'Space'], timeout });
  }

  static waitForArrowKeys(id = 'keyboard-arrows', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { 
      allowedKeys: ['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'], 
      timeout 
    });
  }

  static yesNoResponse(id = 'keyboard-yesno', yesKey = 'y', noKey = 'n', timeout?: number): KeyboardComponent {
    return new KeyboardComponent(id, { 
      allowedKeys: [yesKey, noKey], 
      caseSensitive: false,
      timeout 
    });
  }

  // Override serialize to include component-specific data
  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      options: this.options,
      isListening: this.isListening,
      hasResponded: this.hasResponded,
      startTime: this.startTime,
    };
  }
}

