import type { PrecisionClock } from '@psyforge/timing';
import type { DeviceManager } from '@psyforge/devices';
import type { Scheduler } from '@psyforge/scheduling';

export interface ComponentContext {
  clock: PrecisionClock;
  devices: DeviceManager;
  scheduler: Scheduler;
  canvas?: HTMLCanvasElement;
  container: HTMLElement;
  data: Record<string, unknown>;
  trial?: number;
  block?: number;
}

export interface Transform {
  position: { x: number; y: number; z?: number };
  rotation: number;
  scale: { x: number; y: number };
  opacity: number;
  visible: boolean;
}

export interface ComponentMetadata {
  id: string;
  type: string;
  version: string;
  created: number;
  tags: string[];
  userData: Record<string, unknown>;
}

export abstract class BaseComponent {
  public readonly id: string;
  public readonly type: string;
  protected transform: Transform;
  protected metadata: ComponentMetadata;
  protected isInitialized = false;
  protected isDisposed = false;
  protected children: BaseComponent[] = [];
  protected parent?: BaseComponent;

  constructor(id: string, type: string) {
    this.id = id;
    this.type = type;
    this.transform = {
      position: { x: 0, y: 0 },
      rotation: 0,
      scale: { x: 1, y: 1 },
      opacity: 1,
      visible: true,
    };
    this.metadata = {
      id,
      type,
      version: '1.0.0',
      created: Date.now(),
      tags: [],
      userData: {},
    };
  }

  // Lifecycle methods - must be implemented by subclasses
  abstract onInit(context: ComponentContext): Promise<void>;
  abstract onFrame(deltaTime: number, context: ComponentContext): void;
  abstract onDispose(context: ComponentContext): Promise<void>;

  // Input handling - optional override
  onInput(event: Event, context: ComponentContext): boolean {
    // Return true if event was handled, false to pass to parent
    return false;
  }

  // Fluent API for common transformations
  position(x: number, y: number, z?: number): this {
    this.transform.position = { x, y, z };
    return this;
  }

  rotate(degrees: number): this {
    this.transform.rotation = degrees;
    return this;
  }

  scale(x: number, y?: number): this {
    this.transform.scale = { x, y: y ?? x };
    return this;
  }

  opacity(alpha: number): this {
    this.transform.opacity = Math.max(0, Math.min(1, alpha));
    return this;
  }

  visible(isVisible: boolean): this {
    this.transform.visible = isVisible;
    return this;
  }

  // Hierarchy management
  addChild(child: BaseComponent): this {
    if (child.parent) {
      child.parent.removeChild(child);
    }
    this.children.push(child);
    child.parent = this;
    return this;
  }

  removeChild(child: BaseComponent): boolean {
    const index = this.children.indexOf(child);
    if (index !== -1) {
      this.children.splice(index, 1);
      child.parent = undefined;
      return true;
    }
    return false;
  }

  getChildren(): ReadonlyArray<BaseComponent> {
    return this.children;
  }

  // Metadata management
  tag(...tags: string[]): this {
    this.metadata.tags.push(...tags);
    return this;
  }

  setUserData(key: string, value: unknown): this {
    this.metadata.userData[key] = value;
    return this;
  }

  getUserData<T>(key: string): T | undefined {
    return this.metadata.userData[key] as T;
  }

  // Component lifecycle management
  async initialize(context: ComponentContext): Promise<void> {
    if (this.isInitialized || this.isDisposed) {
      return;
    }

    await this.onInit(context);

    // Initialize children
    for (const child of this.children) {
      await child.initialize(context);
    }

    this.isInitialized = true;
  }

  update(deltaTime: number, context: ComponentContext): void {
    if (!this.isInitialized || this.isDisposed || !this.transform.visible) {
      return;
    }

    this.onFrame(deltaTime, context);

    // Update children
    for (const child of this.children) {
      child.update(deltaTime, context);
    }
  }

  handleInput(event: Event, context: ComponentContext): boolean {
    if (!this.isInitialized || this.isDisposed || !this.transform.visible) {
      return false;
    }

    // Try children first (reverse order for proper z-order)
    for (let i = this.children.length - 1; i >= 0; i--) {
      if (this.children[i].handleInput(event, context)) {
        return true;
      }
    }

    // Try this component
    return this.onInput(event, context);
  }

  async dispose(context: ComponentContext): Promise<void> {
    if (this.isDisposed) {
      return;
    }

    // Dispose children first
    for (const child of this.children) {
      await child.dispose(context);
    }

    await this.onDispose(context);
    this.isDisposed = true;
  }

  // Getters for transform properties
  get worldPosition(): { x: number; y: number; z?: number } {
    if (!this.parent) {
      return this.transform.position;
    }

    const parentPos = this.parent.worldPosition;
    return {
      x: parentPos.x + this.transform.position.x,
      y: parentPos.y + this.transform.position.y,
      z: (parentPos.z ?? 0) + (this.transform.position.z ?? 0),
    };
  }

  get worldOpacity(): number {
    if (!this.parent) {
      return this.transform.opacity;
    }
    return this.parent.worldOpacity * this.transform.opacity;
  }

  // Serialization support
  serialize(): Record<string, unknown> {
    return {
      id: this.id,
      type: this.type,
      transform: this.transform,
      metadata: this.metadata,
      children: this.children.map(child => child.serialize()),
    };
  }

  // Query methods for finding components
  findChildById(id: string): BaseComponent | undefined {
    for (const child of this.children) {
      if (child.id === id) {
        return child;
      }
      const found = child.findChildById(id);
      if (found) {
        return found;
      }
    }
    return undefined;
  }

  findChildrenByType(type: string): BaseComponent[] {
    const results: BaseComponent[] = [];
    for (const child of this.children) {
      if (child.type === type) {
        results.push(child);
      }
      results.push(...child.findChildrenByType(type));
    }
    return results;
  }

  findChildrenByTag(tag: string): BaseComponent[] {
    const results: BaseComponent[] = [];
    for (const child of this.children) {
      if (child.metadata.tags.includes(tag)) {
        results.push(child);
      }
      results.push(...child.findChildrenByTag(tag));
    }
    return results;
  }
}

