import { BaseComponent, type ComponentContext } from '../BaseComponent.js';

export interface TextStyle {
  fontSize?: number | string;
  fontFamily?: string;
  fontWeight?: string | number;
  fontStyle?: 'normal' | 'italic' | 'oblique';
  color?: string;
  backgroundColor?: string;
  textAlign?: 'left' | 'center' | 'right' | 'justify';
  lineHeight?: number | string;
  letterSpacing?: number | string;
  textDecoration?: string;
  textShadow?: string;
  wordWrap?: boolean;
  maxWidth?: number;
  padding?: number | { top: number; right: number; bottom: number; left: number };
}

export interface TextComponentOptions {
  text: string | ((context: ComponentContext) => string);
  style?: TextStyle;
  duration?: number;
  fadeIn?: number;
  fadeOut?: number;
  typewriter?: {
    speed: number; // characters per second
    cursor?: boolean;
    cursorChar?: string;
  };
  responsive?: boolean;
  antiAlias?: boolean;
}

export class TextComponent extends BaseComponent {
  private options: TextComponentOptions;
  private element?: HTMLElement;
  private currentText = '';
  private typewriterTimer?: number;
  private typewriterIndex = 0;
  private durationTimer?: number;
  private fadeTimer?: number;

  constructor(id: string, options: TextComponentOptions) {
    super(id, 'Text');
    this.options = { ...options };
  }

  // Fluent API methods
  text(content: string | ((context: ComponentContext) => string)): this {
    this.options.text = content;
    return this;
  }

  style(styles: Partial<TextStyle>): this {
    this.options.style = { ...this.options.style, ...styles };
    return this;
  }

  fontSize(size: number | string): this {
    this.options.style = { ...this.options.style, fontSize: size };
    return this;
  }

  fontFamily(family: string): this {
    this.options.style = { ...this.options.style, fontFamily: family };
    return this;
  }

  color(textColor: string): this {
    this.options.style = { ...this.options.style, color: textColor };
    return this;
  }

  backgroundColor(bgColor: string): this {
    this.options.style = { ...this.options.style, backgroundColor: bgColor };
    return this;
  }

  textAlign(align: 'left' | 'center' | 'right' | 'justify'): this {
    this.options.style = { ...this.options.style, textAlign: align };
    return this;
  }

  duration(ms: number): this {
    this.options.duration = ms;
    return this;
  }

  fadeIn(ms: number): this {
    this.options.fadeIn = ms;
    return this;
  }

  fadeOut(ms: number): this {
    this.options.fadeOut = ms;
    return this;
  }

  typewriter(speed: number, cursor = false, cursorChar = '|'): this {
    this.options.typewriter = { speed, cursor, cursorChar };
    return this;
  }

  responsive(isResponsive = true): this {
    this.options.responsive = isResponsive;
    return this;
  }

  async onInit(context: ComponentContext): Promise<void> {
    this.element = this.createElement(context);
    context.container.appendChild(this.element);

    // Get text content
    this.currentText = typeof this.options.text === 'function' 
      ? this.options.text(context) 
      : this.options.text;

    // Setup typewriter effect if requested
    if (this.options.typewriter) {
      this.startTypewriter(context);
    } else {
      this.element.textContent = this.currentText;
    }

    // Setup fade in
    if (this.options.fadeIn) {
      this.startFadeIn();
    }

    // Setup duration timer
    if (this.options.duration) {
      this.durationTimer = window.setTimeout(() => {
        if (this.options.fadeOut) {
          this.startFadeOut();
        } else {
          this.visible(false);
        }
      }, this.options.duration);
    }
  }

  onFrame(deltaTime: number, context: ComponentContext): void {
    if (!this.element) return;

    // Update transform
    this.updateElementTransform();

    // Handle responsive text sizing
    if (this.options.responsive) {
      this.handleResponsiveScaling(context);
    }
  }

  async onDispose(context: ComponentContext): Promise<void> {
    this.cleanup();
  }

  private createElement(context: ComponentContext): HTMLElement {
    const element = document.createElement('div');

    // Apply base styles
    element.style.position = 'absolute';
    element.style.pointerEvents = 'none';
    element.style.whiteSpace = this.options.style?.wordWrap ? 'normal' : 'nowrap';

    // Apply text styles
    this.applyTextStyles(element);

    // Apply transform styles
    this.updateElementTransform();

    return element;
  }

  private applyTextStyles(element: HTMLElement): void {
    const style = this.options.style;
    if (!style) return;

    if (style.fontSize) {
      element.style.fontSize = typeof style.fontSize === 'number' 
        ? `${style.fontSize}px` 
        : style.fontSize;
    }
    if (style.fontFamily) element.style.fontFamily = style.fontFamily;
    if (style.fontWeight) element.style.fontWeight = style.fontWeight.toString();
    if (style.fontStyle) element.style.fontStyle = style.fontStyle;
    if (style.color) element.style.color = style.color;
    if (style.backgroundColor) element.style.backgroundColor = style.backgroundColor;
    if (style.textAlign) element.style.textAlign = style.textAlign;
    if (style.lineHeight) {
      element.style.lineHeight = typeof style.lineHeight === 'number' 
        ? style.lineHeight.toString() 
        : style.lineHeight;
    }
    if (style.letterSpacing) {
      element.style.letterSpacing = typeof style.letterSpacing === 'number' 
        ? `${style.letterSpacing}px` 
        : style.letterSpacing;
    }
    if (style.textDecoration) element.style.textDecoration = style.textDecoration;
    if (style.textShadow) element.style.textShadow = style.textShadow;
    if (style.maxWidth) element.style.maxWidth = `${style.maxWidth}px`;

    // Handle padding
    if (style.padding) {
      if (typeof style.padding === 'number') {
        element.style.padding = `${style.padding}px`;
      } else {
        const p = style.padding;
        element.style.padding = `${p.top}px ${p.right}px ${p.bottom}px ${p.left}px`;
      }
    }

    // Anti-aliasing
    if (this.options.antiAlias) {
      element.style.textRendering = 'optimizeLegibility';
      element.style.fontSmooth = 'always';
      element.style.webkitFontSmoothing = 'antialiased';
      element.style.mozOsxFontSmoothing = 'grayscale';
    }
  }

  private updateElementTransform(): void {
    if (!this.element) return;

    const pos = this.worldPosition;

    // Position
    if (this.options.style?.textAlign === 'center') {
      this.element.style.left = `${pos.x}px`;
      this.element.style.top = `${pos.y}px`;
      this.element.style.transform = `translate(-50%, -50%) rotate(${this.transform.rotation}deg) scale(${this.transform.scale.x}, ${this.transform.scale.y})`;
    } else {
      this.element.style.left = `${pos.x}px`;
      this.element.style.top = `${pos.y}px`;
      this.element.style.transform = `rotate(${this.transform.rotation}deg) scale(${this.transform.scale.x}, ${this.transform.scale.y})`;
    }

    // Opacity
    this.element.style.opacity = this.worldOpacity.toString();

    // Visibility
    this.element.style.display = this.transform.visible ? 'block' : 'none';

    // Z-index
    if (this.transform.position.z !== undefined) {
      this.element.style.zIndex = this.transform.position.z.toString();
    }
  }

  private startTypewriter(context: ComponentContext): void {
    if (!this.element || !this.options.typewriter) return;

    this.typewriterIndex = 0;
    this.element.textContent = this.options.typewriter.cursor ? this.options.typewriter.cursorChar || '|' : '';

    const intervalMs = 1000 / this.options.typewriter.speed;

    this.typewriterTimer = window.setInterval(() => {
      if (!this.element || this.typewriterIndex >= this.currentText.length) {
        this.finishTypewriter();
        return;
      }

      const displayText = this.currentText.substring(0, this.typewriterIndex + 1);
      this.element.textContent = displayText + 
        (this.options.typewriter!.cursor ? (this.options.typewriter!.cursorChar || '|') : '');

      this.typewriterIndex++;
    }, intervalMs);
  }

  private finishTypewriter(): void {
    if (this.typewriterTimer) {
      clearInterval(this.typewriterTimer);
      this.typewriterTimer = undefined;
    }

    if (this.element) {
      this.element.textContent = this.currentText;
    }
  }

  private startFadeIn(): void {
    if (!this.element || !this.options.fadeIn) return;

    this.element.style.opacity = '0';

    const startTime = performance.now();
    const fadeInDuration = this.options.fadeIn;

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / fadeInDuration, 1);

      if (this.element) {
        const opacity = progress * this.worldOpacity;
        this.element.style.opacity = opacity.toString();
      }

      if (progress < 1) {
        requestAnimationFrame(animate);
      }
    };

    requestAnimationFrame(animate);
  }

  private startFadeOut(): void {
    if (!this.element || !this.options.fadeOut) return;

    const startOpacity = this.worldOpacity;
    const startTime = performance.now();
    const fadeOutDuration = this.options.fadeOut;

    const animate = (currentTime: number) => {
      const elapsed = currentTime - startTime;
      const progress = Math.min(elapsed / fadeOutDuration, 1);

      if (this.element) {
        const opacity = startOpacity * (1 - progress);
        this.element.style.opacity = opacity.toString();
      }

      if (progress >= 1) {
        this.visible(false);
      } else {
        requestAnimationFrame(animate);
      }
    };

    requestAnimationFrame(animate);
  }

  private handleResponsiveScaling(context: ComponentContext): void {
    if (!this.element) return;

    const container = context.container;
    const containerWidth = container.clientWidth;
    const containerHeight = container.clientHeight;

    // Simple responsive scaling based on container size
    // This is a basic implementation - could be much more sophisticated
    const baseWidth = 1920; // Reference width
    const scaleFactor = containerWidth / baseWidth;

    if (scaleFactor !== 1) {
      const currentScale = this.transform.scale.x;
      this.scale(currentScale * scaleFactor);
    }
  }

  private cleanup(): void {
    if (this.typewriterTimer) {
      clearInterval(this.typewriterTimer);
      this.typewriterTimer = undefined;
    }

    if (this.durationTimer) {
      clearTimeout(this.durationTimer);
      this.durationTimer = undefined;
    }

    if (this.fadeTimer) {
      clearTimeout(this.fadeTimer);
      this.fadeTimer = undefined;
    }

    if (this.element && this.element.parentNode) {
      this.element.parentNode.removeChild(this.element);
      this.element = undefined;
    }
  }

  // Override serialize to include component-specific data
  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      options: {
        ...this.options,
        text: typeof this.options.text === 'string' ? this.options.text : '[Function]',
      },
    };
  }
}

