// 🚀 ENHANCED FORGESCRIPT FLUENT API & COMPILER - Primary API (Sprint 2)
export { 
  FluentExperimentBuilder,
  experiment,
  conditions,
  trial,
  type PowerAnalysisOptions,
  type PowerAnalysisResult,
  type ConditionBuilder,
  type TrialBuilder
} from './api/FluentExperimentBuilder.js';

// ForgeScript Compiler & FZB Binary Format
export {
  ForgeScriptCompiler,
  compileExperiment,
  decompileExperiment,
  type CompilerOptions,
  type CompilerResult,
  type CompilerError,
  type CompilerWarning,
  type CompilerMetadata,
