import type { Experiment, ExperimentData } from './Experiment.js';
import type { PrecisionClock } from '@psyforge/timing';
import type { Scheduler } from '@psyforge/scheduling';
import type { DeviceManager } from '@psyforge/devices';

export interface RuntimeConfiguration {
  enableTiming?: boolean;
  enableDevices?: boolean;
  enableDebugging?: boolean;
  logLevel?: 'debug' | 'info' | 'warn' | 'error';
  maxExecutionTime?: number;
  errorRecovery?: boolean;
}

export interface RuntimeCapabilities {
  hasHighPrecisionTiming: boolean;
  hasWebAudio: boolean;
  hasFullscreen: boolean;
  hasTouch: boolean;
  hasGamepad: boolean;
  hasWebGL: boolean;
  supportedAudioFormats: string[];
  supportedVideoFormats: string[];
  supportedImageFormats: string[];
}

export class Runtime {
  private static instance?: Runtime;
  private config: RuntimeConfiguration;
  private capabilities?: RuntimeCapabilities;
  private clock?: PrecisionClock;
  private scheduler?: Scheduler;
  private deviceManager?: DeviceManager;
  private activeExperiment?: Experiment;

  private constructor(config: RuntimeConfiguration = {}) {
    this.config = {
      enableTiming: true,
      enableDevices: true,
      enableDebugging: false,
      logLevel: 'info',
      maxExecutionTime: 300000, // 5 minutes
      errorRecovery: true,
      ...config,
    };
  }

  static getInstance(config?: RuntimeConfiguration): Runtime {
    if (!Runtime.instance) {
      Runtime.instance = new Runtime(config);
    }
    return Runtime.instance;
  }

  async initialize(): Promise<void> {
    this.log('info', 'Initializing ForgeScript Runtime...');

    try {
      // Detect capabilities
      this.capabilities = await this.detectCapabilities();
      this.log('debug', 'Capabilities detected:', this.capabilities);

      // Initialize timing system
      if (this.config.enableTiming) {
        await this.initializeTiming();
      }

      // Initialize device management
      if (this.config.enableDevices) {
        await this.initializeDevices();
      }

      this.log('info', 'ForgeScript Runtime initialized successfully');
    } catch (error) {
      this.log('error', 'Failed to initialize runtime:', error);
      throw error;
    }
  }

  private async detectCapabilities(): Promise<RuntimeCapabilities> {
    const capabilities: RuntimeCapabilities = {
      hasHighPrecisionTiming: 'performance' in window && 'now' in performance,
      hasWebAudio: 'AudioContext' in window || 'webkitAudioContext' in window,
      hasFullscreen: 'requestFullscreen' in document.documentElement,
      hasTouch: 'ontouchstart' in window,
      hasGamepad: 'getGamepads' in navigator,
      hasWebGL: this.checkWebGLSupport(),
      supportedAudioFormats: this.getSupportedAudioFormats(),
      supportedVideoFormats: this.getSupportedVideoFormats(),
      supportedImageFormats: this.getSupportedImageFormats(),
    };

    return capabilities;
  }

  private checkWebGLSupport(): boolean {
    try {
      const canvas = document.createElement('canvas');
      const gl = canvas.getContext('webgl') || canvas.getContext('experimental-webgl');
      return gl !== null;
    } catch (error) {
      return false;
    }
  }

  private getSupportedAudioFormats(): string[] {
    const audio = document.createElement('audio');
    const formats: string[] = [];

    const testFormats = [
      { type: 'audio/mpeg', ext: 'mp3' },
      { type: 'audio/ogg', ext: 'ogg' },
      { type: 'audio/wav', ext: 'wav' },
      { type: 'audio/mp4', ext: 'm4a' },
      { type: 'audio/webm', ext: 'webm' },
    ];

    for (const format of testFormats) {
      if (audio.canPlayType(format.type) !== '') {
        formats.push(format.ext);
      }
    }

    return formats;
  }

  private getSupportedVideoFormats(): string[] {
    const video = document.createElement('video');
    const formats: string[] = [];

    const testFormats = [
      { type: 'video/mp4', ext: 'mp4' },
      { type: 'video/webm', ext: 'webm' },
      { type: 'video/ogg', ext: 'ogv' },
      { type: 'video/quicktime', ext: 'mov' },
    ];

    for (const format of testFormats) {
      if (video.canPlayType(format.type) !== '') {
        formats.push(format.ext);
      }
    }

    return formats;
  }

  private getSupportedImageFormats(): string[] {
    // Most browsers support these formats
    return ['jpg', 'jpeg', 'png', 'gif', 'svg', 'webp', 'bmp'];
  }

  private async initializeTiming(): Promise<void> {
    try {
      const { PrecisionClock } = await import('@psyforge/timing');
      const { createScheduler } = await import('@psyforge/scheduling');

      this.clock = new PrecisionClock();
      this.scheduler = createScheduler(this.clock);

      this.log('debug', 'Timing system initialized');
    } catch (error) {
      this.log('error', 'Failed to initialize timing system:', error);
      throw error;
    }
  }

  private async initializeDevices(): Promise<void> {
    try {
      const { DeviceManager } = await import('@psyforge/devices');

      this.deviceManager = new DeviceManager();
      await this.deviceManager.initialize();

      this.log('debug', 'Device management initialized');
    } catch (error) {
      this.log('error', 'Failed to initialize device management:', error);
      throw error;
    }
  }

  async runExperiment(experiment: Experiment, participantId?: string): Promise<ExperimentData> {
    if (this.activeExperiment) {
      throw new Error('Another experiment is already running');
    }

    if (!this.capabilities) {
      throw new Error('Runtime not initialized. Call initialize() first.');
    }

    this.log('info', `Starting experiment: ${experiment.getMetadata().title}`);

    try {
      this.activeExperiment = experiment;

      // Set up timeout if configured
      let timeoutId: number | undefined;
      if (this.config.maxExecutionTime) {
        timeoutId = window.setTimeout(() => {
          this.log('warn', 'Experiment execution timeout reached');
          this.stopExperiment();
        }, this.config.maxExecutionTime);
      }

      // Run the experiment
      const data = await experiment.run(participantId);

      // Clear timeout
      if (timeoutId !== undefined) {
        clearTimeout(timeoutId);
      }

      this.log('info', 'Experiment completed successfully');
      return data;

    } catch (error) {
      this.log('error', 'Experiment execution failed:', error);

      if (this.config.errorRecovery) {
        this.log('info', 'Attempting error recovery...');
        // Implement error recovery logic here
      }

      throw error;
    } finally {
      this.activeExperiment = undefined;
    }
  }

  stopExperiment(): void {
    if (this.activeExperiment) {
      this.log('info', 'Stopping active experiment');
      this.activeExperiment.stop();
      this.activeExperiment = undefined;
    }
  }

  getCapabilities(): RuntimeCapabilities | undefined {
    return this.capabilities ? { ...this.capabilities } : undefined;
  }

  getConfiguration(): RuntimeConfiguration {
    return { ...this.config };
  }

  updateConfiguration(newConfig: Partial<RuntimeConfiguration>): void {
    this.config = { ...this.config, ...newConfig };
    this.log('debug', 'Configuration updated:', this.config);
  }

  getClock(): PrecisionClock | undefined {
    return this.clock;
  }

  getScheduler(): Scheduler | undefined {
    return this.scheduler;
  }

  getDeviceManager(): DeviceManager | undefined {
    return this.deviceManager;
  }

  isExperimentRunning(): boolean {
    return this.activeExperiment !== undefined;
  }

  getActiveExperiment(): Experiment | undefined {
    return this.activeExperiment;
  }

  private log(level: 'debug' | 'info' | 'warn' | 'error', message: string, ...args: unknown[]): void {
    const levels = ['debug', 'info', 'warn', 'error'];
    const currentLevelIndex = levels.indexOf(this.config.logLevel || 'info');
    const messageLevelIndex = levels.indexOf(level);

    if (messageLevelIndex >= currentLevelIndex) {
      const timestamp = new Date().toISOString();
      const prefix = `[${timestamp}] [ForgeScript] [${level.toUpperCase()}]`;

      switch (level) {
        case 'debug':
          console.debug(prefix, message, ...args);
          break;
        case 'info':
          console.info(prefix, message, ...args);
          break;
        case 'warn':
          console.warn(prefix, message, ...args);
          break;
        case 'error':
          console.error(prefix, message, ...args);
          break;
      }
    }
  }

  // Static helper methods for common runtime operations
  static async createAndInitialize(config?: RuntimeConfiguration): Promise<Runtime> {
    const runtime = Runtime.getInstance(config);
    await runtime.initialize();
    return runtime;
  }

  static async quickRun(experiment: Experiment, participantId?: string): Promise<ExperimentData> {
    const runtime = await Runtime.createAndInitialize();
    return await runtime.runExperiment(experiment, participantId);
  }
}

