import { z } from 'zod';
import type { Experiment } from '../core/Experiment.js';
import type { Timeline } from '../core/Timeline.js';
import { TextStimulus } from '../stimuli/Text.js';
import { ImageStimulus } from '../stimuli/Image.js';
import { AudioStimulus } from '../stimuli/Audio.js';
import { VideoStimulus } from '../stimuli/Video.js';
import { KeyboardResponse } from '../responses/KeyboardResponse.js';
import { MouseResponse } from '../responses/MouseResponse.js';
import { TouchResponse } from '../responses/TouchResponse.js';
import { WaitEvent, LoopEvent } from '../core/Event.js';

export interface SerializationOptions {
  includeMetadata?: boolean;
  includeResponseData?: boolean;
  format?: 'json' | 'compact';
  version?: string;
}

export interface SerializedExperiment {
  type: 'ForgeScriptExperiment';
  version: string;
  timestamp: number;
  data: Record<string, unknown>;
}

export class Serializer {
  private static readonly VERSION = '1.0.0';
  private static readonly TYPE_REGISTRY = new Map<string, new (...args: any[]) => any>([
    ['TextStimulus', TextStimulus],
    ['ImageStimulus', ImageStimulus],
    ['AudioStimulus', AudioStimulus],
    ['VideoStimulus', VideoStimulus],
    ['KeyboardResponse', KeyboardResponse],
    ['MouseResponse', MouseResponse],
    ['TouchResponse', TouchResponse],
    ['WaitEvent', WaitEvent],
    ['LoopEvent', LoopEvent],
  ]);

  static serialize(experiment: Experiment, options: SerializationOptions = {}): SerializedExperiment {
    const opts: Required<SerializationOptions> = {
      includeMetadata: true,
      includeResponseData: false,
      format: 'json',
      version: Serializer.VERSION,
      ...options,
    };

    const data = experiment.serialize();

    // Remove non-essential data if compact format
    if (opts.format === 'compact') {
      // Remove metadata if not requested
      if (!opts.includeMetadata) {
        delete (data as any).metadata;
      }

      // Remove response data if not requested
      if (!opts.includeResponseData) {
        // This would recursively remove response data from timelines
        Serializer.removeResponseData(data);
      }
    }

    return {
      type: 'ForgeScriptExperiment',
      version: opts.version,
      timestamp: Date.now(),
      data,
    };
  }

  static deserialize(serialized: SerializedExperiment): Experiment {
    // Validate the serialized data structure
    const schema = z.object({
      type: z.literal('ForgeScriptExperiment'),
      version: z.string(),
      timestamp: z.number(),
      data: z.record(z.unknown()),
    });

    const parsed = schema.parse(serialized);

    // Check version compatibility
    if (!Serializer.isVersionCompatible(parsed.version)) {
      throw new Error(`Incompatible ForgeScript version: ${parsed.version}. Expected: ${Serializer.VERSION}`);
    }

    // Deserialize the experiment
    return Experiment.deserialize(parsed.data);
  }

  static stringify(experiment: Experiment, options: SerializationOptions = {}): string {
    const serialized = Serializer.serialize(experiment, options);
    return JSON.stringify(serialized, null, options.format === 'compact' ? 0 : 2);
  }

  static parse(jsonString: string): Experiment {
    try {
      const parsed = JSON.parse(jsonString);
      return Serializer.deserialize(parsed);
    } catch (error) {
      throw new Error(`Failed to parse ForgeScript experiment: ${error}`);
    }
  }

  static registerType(typeName: string, constructor: new (...args: any[]) => any): void {
    Serializer.TYPE_REGISTRY.set(typeName, constructor);
  }

  static getRegisteredTypes(): string[] {
    return Array.from(Serializer.TYPE_REGISTRY.keys());
  }

  static deserializeItem(data: Record<string, unknown>): any {
    const schema = z.object({
      type: z.string(),
    });

    const parsed = schema.parse(data);
    const constructor = Serializer.TYPE_REGISTRY.get(parsed.type);

    if (!constructor) {
      throw new Error(`Unknown item type: ${parsed.type}`);
    }

    // Check if the constructor has a deserialize method
    if ('deserialize' in constructor && typeof constructor.deserialize === 'function') {
      return constructor.deserialize(data);
    }

    throw new Error(`Type ${parsed.type} does not support deserialization`);
  }

  private static removeResponseData(data: any): void {
    if (typeof data === 'object' && data !== null) {
      if (Array.isArray(data)) {
        data.forEach(item => Serializer.removeResponseData(item));
      } else {
        // Remove response data fields
        delete data.responseData;
        delete data.responses;
        delete data.collectedData;

        // Recursively process nested objects
        Object.values(data).forEach(value => Serializer.removeResponseData(value));
      }
    }
  }

  private static isVersionCompatible(version: string): boolean {
    // Simple version compatibility check
    // In a real implementation, this would use semantic versioning
    const [major, minor] = version.split('.').map(Number);
    const [currentMajor, currentMinor] = Serializer.VERSION.split('.').map(Number);

    // Compatible if major version matches and minor version is <= current
    return major === currentMajor && minor <= currentMinor;
  }

  // Utility methods for working with serialized data
  static getExperimentInfo(serialized: SerializedExperiment): {
    title: string;
    version: string;
    author?: string;
    created: number;
    modified: number;
  } {
    const data = serialized.data as any;
    const metadata = data.metadata || {};

    return {
      title: metadata.title || 'Untitled Experiment',
      version: metadata.version || '1.0.0',
      author: metadata.author,
      created: metadata.created || serialized.timestamp,
      modified: metadata.modified || serialized.timestamp,
    };
  }

  static validateExperiment(serialized: SerializedExperiment): { valid: boolean; errors: string[] } {
    const errors: string[] = [];

    try {
      // Basic structure validation
      const schema = z.object({
        type: z.literal('ForgeScriptExperiment'),
        version: z.string(),
        timestamp: z.number(),
        data: z.object({
          metadata: z.object({
            title: z.string().min(1, 'Title cannot be empty'),
            version: z.string().min(1, 'Version cannot be empty'),
          }),
          timelines: z.array(z.record(z.unknown())).min(1, 'At least one timeline is required'),
        }),
      });

      schema.parse(serialized);

      // Version compatibility check
      if (!Serializer.isVersionCompatible(serialized.version)) {
        errors.push(`Incompatible version: ${serialized.version}`);
      }

      // Timeline validation
      const data = serialized.data as any;
      if (data.timelines) {
        for (let i = 0; i < data.timelines.length; i++) {
          const timeline = data.timelines[i];
          if (!timeline.items || timeline.items.length === 0) {
            errors.push(`Timeline ${i + 1} is empty`);
          }
        }
      }

    } catch (error) {
      if (error instanceof z.ZodError) {
        errors.push(...error.errors.map(e => e.message));
      } else {
        errors.push(`Validation error: ${error}`);
      }
    }

    return {
      valid: errors.length === 0,
      errors,
    };
  }

  // Convert between different ForgeScript versions
  static migrate(serialized: SerializedExperiment, targetVersion: string): SerializedExperiment {
    // This would implement migration logic between versions
    // For now, just update the version field
    return {
      ...serialized,
      version: targetVersion,
      timestamp: Date.now(),
    };
  }
}
